                'upsert' => 'Create a record if it does not exist, otherwise update it',
                'update' => 'Update records only',
            ],
            default: 'create',
        );

        if (in_array($this->resolutionMode, ['upsert', 'update'])) {
            $this->resolutionColumn = text(
                label: 'What column should be used to find existing records?',
                placeholder: 'slug',
                required: true,
            );
        }
    }

public function getAuthorizationResponseWithMessage(): Response
    {
        $response = $this->getAuthorizationResponse();

        if ($response->allowed()) {
            return $response;
        }

        $message = $this->getAuthorizationMessage();

        if (filled($message)) {
            invade($response)->message = $message; /** @phpstan-ignore-line */

            return $response;
        }

        if (blank($response->message())) {
            throw new LogicException('An authorization was denied without a message.');
        }

        return $response;
    }

public function getIndividualRecordAuthorizationResponse(Model $record): Response
    {
        if (is_string($this->authorizeIndividualRecords)) {
            return Gate::inspect($this->authorizeIndividualRecords, Arr::wrap($record));
        }

        $resolver = ($this->authorizeIndividualRecords instanceof Closure)
            ? $this->authorizeIndividualRecords
            : $this->getHasActionsLivewire()->getDefaultActionIndividualRecordAuthorizationResponseResolver($this);

        if (! $resolver) {
            throw new LogicException('No function was passed to [authorizeIndividualRecords()].');
        }

        $response = $resolver($record);

        if ($response instanceof Response) {
            return $response;
        }

        return $response ? Response::allow() : Response::deny();
    }

static function insertAttributesIntoHtmlRoot($html, $attributes) {
    $attributesFormattedForHtmlElement = static::stringifyHtmlAttributes($attributes);

    preg_match('/(?:\n\s*|^\s*)<([a-zA-Z0-9\-]+)/', $html, $matches, PREG_OFFSET_CAPTURE);

    throw_unless(
        count($matches),
        new RootTagMissingFromViewException
    );

    $tagName = $matches[1][0];
    $lengthOfTagName = strlen($tagName);
    $positionOfFirstCharacterInTagName = $matches[1][1];

    return substr_replace(
        $html,
        ' '.$attributesFormattedForHtmlElement,
        $positionOfFirstCharacterInTagName + $lengthOfTagName,
        0
    );
}

protected function injectUseStatementsFromClassPortion(string $contents, string $classPortion): string
    {
        // Extract everything between <?php and "new"
        if (preg_match('/\<\?php(.*?)new/s', $classPortion, $matches)) {
            $preamble = $matches[1];

            // Use (*SKIP)(*FAIL) to ignore "use" statements inside comments...
            $skipComments = '(?:\/\/[^\n]*|\/\*.*?\*\/)(*SKIP)(*FAIL)';

            // Extract all use statements
            if (preg_match_all('/' . $skipComments . '|use\s+[^;]+;/s', $preamble, $useMatches)) {
                $useStatements = implode("\n", $useMatches[0]);
            }
        }

        // Only add PHP tags and use statements if we found any
        if (isset($useStatements) && $useStatements) {
            $contents = "<?php\n" . $useStatements . "\n?>\n\n" . $contents;
        }

        return $contents;
    }

protected function filterAttributes($data, $rules)
    {
        $filteredAttributes = [];

        foreach($rules as $key => $rule) {
            // If the rule is an array, take the key instead
            if (is_array($rule)) {
                $rule = $key;
            }

            // If someone has created an empty model, the attribute may not exist
            // yet, so use data_get so it will still be sent to the front end.
            $filteredAttributes[$rule] = data_get($data, $rule);
        }

        return $filteredAttributes;
    }

